-- ===== SET 11 =====

-- Passage 1: Cognitive psychology & decision making
INSERT INTO questions (practice_set_id, question_order, question_text, answer_option_1, answer_option_2, answer_option_3, answer_option_4, correct_answer_number) VALUES
(11, 1,
'מחקרים עדכניים בפסיכולוגיה הקוגניטיבית מראים כי קבלת החלטות אנושית מושפעת באופן משמעותי מגורמים לא-מודעים, בניגוד לדעה הרווחת לפיה הכרעות נובעות מהיגיון ותבונה. ניסויים שנערכו על אוכלוסיות שונות מצביעים על כך שההקשר הסביבתי, המצב הרגשי, ואף גורמים פיזיים כמו רמת עייפות, משפיעים על תוצאת ההחלטה יותר מתוכן המידע עצמו. ממצאים אלה מערערים את ההנחה הבסיסית של המודל הכלכלי הקלאסי בדבר האדם הרציונלי.
מה ניתן להסיק מהמחקר לגבי המודל הכלכלי הקלאסי?',
'הוא מאושרת על ידי הממצאים', 'הוא נכון רק בתנאי לחץ', 'הוא מוטל בספק לאור הממצאים', 'הוא מוכח כשגוי לחלוטין', 3),

(11, 2,
'מחקרים עדכניים בפסיכולוגיה הקוגניטיבית מראים כי קבלת החלטות אנושית מושפעת באופן משמעותי מגורמים לא-מודעים, בניגוד לדעה הרווחת לפיה הכרעות נובעות מהיגיון ותבונה. ניסויים שנערכו על אוכלוסיות שונות מצביעים על כך שההקשר הסביבתי, המצב הרגשי, ואף גורמים פיזיים כמו רמת עייפות, משפיעים על תוצאת ההחלטה יותר מתוכן המידע עצמו. ממצאים אלה מערערים את ההנחה הבסיסית של המודל הכלכלי הקלאסי בדבר האדם הרציונלי.
מה מאפיין את הגורמים שהמחקר מוצא כמשפיעים ביותר על ההחלטה?',
'הם קשורים לאיכות המידע', 'הם חיצוניים לתוכן ההחלטה', 'הם תלויים ברמת ההשכלה', 'הם ניתנים לשליטה מלאה', 2);

-- Passage 2: Game theory & strategic behavior
INSERT INTO questions (practice_set_id, question_order, question_text, answer_option_1, answer_option_2, answer_option_3, answer_option_4, correct_answer_number) VALUES
(11, 3,
'תורת המשחקים, שפותחה במקור לניתוח קונפליקטים צבאיים וכלכליים, מניחה כי שחקנים רציונליים יבחרו תמיד בפעולה שתמקסם את הרווח האישי שלהם. אולם, ניסויים אמפיריים חוזרים ונשנים — ובמיוחד משחק ה"דילמה של האסיר" — מראים כי בני אדם נוטים לשיתוף פעולה גם כשהאינטרס האישי הצר מכתיב בגידה. פרדוקס זה הוביל לפיתוח מודלים מורכבים יותר הכוללים גורמי אמון, מוניטין ואבולוציה תרבותית.
מה מגלים הניסויים האמפיריים בניגוד להנחת תורת המשחקים הקלאסית?',
'בני אדם תמיד מעדיפים רווח אישי', 'בני אדם נוטים לשיתוף פעולה גם ללא תמריץ אישי ברור', 'תורת המשחקים נכונה בכל מצב', 'רווח קבוצתי שווה תמיד לרווח אישי', 2),

(11, 4,
'תורת המשחקים, שפותחה במקור לניתוח קונפליקטים צבאיים וכלכליים, מניחה כי שחקנים רציונליים יבחרו תמיד בפעולה שתמקסם את הרווח האישי שלהם. אולם, ניסויים אמפיריים חוזרים ונשנים — ובמיוחד משחק ה"דילמה של האסיר" — מראים כי בני אדם נוטים לשיתוף פעולה גם כשהאינטרס האישי הצר מכתיב בגידה. פרדוקס זה הוביל לפיתוח מודלים מורכבים יותר הכוללים גורמי אמון, מוניטין ואבולוציה תרבותית.
מה הוביל לפיתוח המודלים המורכבים יותר?',
'כשל טכנולוגי בניסויים', 'ממצאים שסתרו את הנחות הבסיס', 'בקשת ממשלות לכלי ניתוח חדשים', 'גילוי שגיאות מתמטיות במודל המקורי', 2);

-- Passage 3: Neuroscience & neuroplasticity
INSERT INTO questions (practice_set_id, question_order, question_text, answer_option_1, answer_option_2, answer_option_3, answer_option_4, correct_answer_number) VALUES
(11, 5,
'גמישות עצבית — היכולת של המוח לארגן מחדש את קישוריו העצביים בתגובה לניסיון — הפכה לאחד המושגים המהפכניים ביותר בנוירולוגיה המודרנית. בעוד שבעבר האמינו המדענים כי מבנה המוח קבוע לאחר שלב ההתפתחות המוקדמת, מחקרים עדכניים מוכיחים כי שינויים מבניים מתרחשים לאורך כל חיי האדם בתגובה ללמידה, אימון ואפילו פגיעה. השלכה מרכזית של ממצאים אלה היא כי תוכניות שיקום לאחר פגיעות מוחיות יכולות להיות אפקטיביות בהרבה ממה שנחשב בעבר.
מה היה האמונה המדעית המקורית שנסתרה על ידי מחקרים עדכניים?',
'מוח האדם ממשיך לצמוח לאחר הבגרות', 'מבנה המוח קבוע ואינו משתנה לאחר ההתפתחות הראשונית', 'למידה אינה משפיעה על המוח', 'פגיעות מוחיות אינן ניתנות לשיקום', 2),

(11, 6,
'גמישות עצבית — היכולת של המוח לארגן מחדש את קישוריו העצביים בתגובה לניסיון — הפכה לאחד המושגים המהפכניים ביותר בנוירולוגיה המודרנית. בעוד שבעבר האמינו המדענים כי מבנה המוח קבוע לאחר שלב ההתפתחות המוקדמת, מחקרים עדכניים מוכיחים כי שינויים מבניים מתרחשים לאורך כל חיי האדם בתגובה ללמידה, אימון ואפילו פגיעה. השלכה מרכזית של ממצאים אלה היא כי תוכניות שיקום לאחר פגיעות מוחיות יכולות להיות אפקטיביות בהרבה ממה שנחשב בעבר.
מה ההשלכה המעשית המרכזית שמוזכרת בקטע?',
'ניתן ללמוד כל מיומנות בכל גיל ללא מאמץ', 'פגיעות מוחיות אינן גורמות לנזק קבוע', 'פוטנציאל השיקום לאחר פגיעות מוחיות גבוה ממה שחשבו', 'למידה בילדות חשובה יותר מבגרות', 3);

-- Passage 4: Environmental economics & externalities
INSERT INTO questions (practice_set_id, question_order, question_text, answer_option_1, answer_option_2, answer_option_3, answer_option_4, correct_answer_number) VALUES
(11, 7,
'כלכלת הסביבה עוסקת בתופעת "הכשל השוקי" הנוצרת כאשר עלויות סביבתיות — כגון זיהום אוויר ומים — אינן נכללות במחיר המוצר או השירות הגורם להן. בהיעדר מנגנון מחירים שמשקף את העלות האמיתית לחברה, יצרנים נוטים לייצר יתר על המידה ולצרכנים אין תמריץ להפחית צריכה. פתרון אחד שהציע הכלכלן ארתור פיגו הוא הטלת מס על גורמי הזיהום בגובה הנזק הסביבתי — פתרון הידוע כ"מס פיגוביאני" — כדי להכניס את הסביבה חזרה לחשבון הכלכלי.
מהי ה"כשל השוקי" כפי שמוסבר בקטע?',
'כאשר חברות מרוויחות יותר מהצפוי', 'כאשר מחיר השוק אינו משקף עלויות חברתיות אמיתיות', 'כאשר הממשלה מתערבת בשוק', 'כאשר הצריכה עולה על ההיצע', 2),

(11, 8,
'כלכלת הסביבה עוסקת בתופעת "הכשל השוקי" הנוצרת כאשר עלויות סביבתיות — כגון זיהום אוויר ומים — אינן נכללות במחיר המוצר או השירות הגורם להן. בהיעדר מנגנון מחירים שמשקף את העלות האמיתית לחברה, יצרנים נוטים לייצר יתר על המידה ולצרכנים אין תמריץ להפחית צריכה. פתרון אחד שהציע הכלכלן ארתור פיגו הוא הטלת מס על גורמי הזיהום בגובה הנזק הסביבתי — פתרון הידוע כ"מס פיגוביאני" — כדי להכניס את הסביבה חזרה לחשבון הכלכלי.
מהו הרציונל של "מס פיגוביאני"?',
'ענישת חברות מזהמות', 'יצירת הכנסה ממשלתית לשמירה על הסביבה', 'שיקוף עלות הנזק הסביבתי במחיר השוק', 'תמרוץ פיתוח טכנולוגיה ירוקה', 3);

-- Passage 5: Philosophy of science & falsifiability
INSERT INTO questions (practice_set_id, question_order, question_text, answer_option_1, answer_option_2, answer_option_3, answer_option_4, correct_answer_number) VALUES
(11, 9,
'קרל פופר טען כי הקריטריון המבחין בין מדע לבין פסאודו-מדע אינו היכולת לאשש תיאוריה, אלא היכולת להפריכה. לפי עמדה זו, תיאוריה מדעית אמיתית חייבת להיות "הפרכה פוטנציאלית" — כלומר ניתן להגדיר ניסוי שיוכל להוכיח שהיא שגויה. תיאוריות שאינן ניתנות להפרכה עקרונית — כמו חלק מהפסיכואנליזה — אינן מדע אמיתי לדעת פופר, גם אם הן מסוגלות להסביר כל תצפית. גישה זו שינתה את האופן שבו פילוסופים ומדענים מגדירים את גבולות הידע המדעי.
מהו הקריטריון המרכזי שפופר מציע למדע אמיתי?',
'יכולת ניבוי מדויקת', 'אישור על ידי ניסויים רבים', 'האפשרות להפריך את התיאוריה', 'הסכמה בין מדענים', 3),

(11, 10,
'קרל פופר טען כי הקריטריון המבחין בין מדע לבין פסאודו-מדע אינו היכולת לאשש תיאוריה, אלא היכולת להפריכה. לפי עמדה זו, תיאוריה מדעית אמיתית חייבת להיות "הפרכה פוטנציאלית" — כלומר ניתן להגדיר ניסוי שיוכל להוכיח שהיא שגויה. תיאוריות שאינן ניתנות להפרכה עקרונית — כמו חלק מהפסיכואנליזה — אינן מדע אמיתי לדעת פופר, גם אם הן מסוגלות להסביר כל תצפית. גישה זו שינתה את האופן שבו פילוסופים ומדענים מגדירים את גבולות הידע המדעי.
מה מרמז פופר לגבי תיאוריה שמסוגלת להסביר כל תצפית?',
'היא מדע מושלם', 'קיבולת הסבר גבוהה מעידה על נכונותה', 'אם אינה ניתנת להפרכה — היא אינה מדע', 'היא מועדפת על תיאוריות מוגבלות יותר', 3);

-- ===== SET 12 =====

-- Passage 1: Information asymmetry & markets
INSERT INTO questions (practice_set_id, question_order, question_text, answer_option_1, answer_option_2, answer_option_3, answer_option_4, correct_answer_number) VALUES
(12, 1,
'ג''ורג'' אקרלוף הדגים בעבודתו "שוק הלימונים" כיצד אסימטריית מידע — מצב שבו אחד הצדדים לעסקה יודע יותר מהשני — מובילה לקריסת שווקים. במקרה של שוק מכוניות יד, המוכר יודע את מצב הרכב טוב יותר מהקונה. כתוצאה מכך, קונים פוטנציאליים מציעים מחיר ממוצע — שמתאים לרכב באיכות ממוצעת — ובעלי רכבים איכותיים מוציאים את רכביהם מהשוק כיוון שאינם מקבלים מחיר הוגן. תהליך זה מותיר בשוק רכבים ירודים בלבד — "לימונים" — וחוזר על עצמו עד להתמוטטות השוק.
מדוע בעלי רכבים איכותיים עוזבים את השוק?',
'כי הם מעדיפים שלא למכור בכלל', 'כי אין להם צורך בכסף', 'כי הקונים אינם מוכנים לשלם את המחיר ההוגן עבורם', 'כי הממשלה אוסרת על מכירתם', 3),

(12, 2,
'ג''ורג'' אקרלוף הדגים בעבודתו "שוק הלימונים" כיצד אסימטריית מידע — מצב שבו אחד הצדדים לעסקה יודע יותר מהשני — מובילה לקריסת שווקים. במקרה של שוק מכוניות יד, המוכר יודע את מצב הרכב טוב יותר מהקונה. כתוצאה מכך, קונים פוטנציאליים מציעים מחיר ממוצע — שמתאים לרכב באיכות ממוצעת — ובעלי רכבים איכותיים מוציאים את רכביהם מהשוק כיוון שאינם מקבלים מחיר הוגן. תהליך זה מותיר בשוק רכבים ירודים בלבד — "לימונים" — וחוזר על עצמו עד להתמוטטות השוק.
מה מסמל המושג "לימון" במאמרו של אקרלוף?',
'רכב בצבע צהוב', 'מוצר ירוד שנשאר בשוק בעקבות כשל מידע', 'קונה שנוהג בחוסר תום לב', 'עסקה כלכלית בלתי-חוקית', 2);

-- Passage 2: Cognitive dissonance
INSERT INTO questions (practice_set_id, question_order, question_text, answer_option_1, answer_option_2, answer_option_3, answer_option_4, correct_answer_number) VALUES
(12, 3,
'ליאון פסטינגר הציג את תיאוריית הדיסוננס הקוגניטיבי — המצב הפסיכולוגי שנוצר כאשר אדם מחזיק בשתי אמונות סותרות בו-זמנית, או כאשר מעשיו סותרים את אמונותיו. לפי פסטינגר, המוח אינו יכול לסבול מתח זה לאורך זמן ולכן ישאף להפחיתו — בין אם על ידי שינוי האמונה, שינוי ההתנהגות, או — נפוץ יותר — על ידי הצדקה פסיכולוגית שמפחיתה את ה"איום" של המידע הסותר. ממצא זה מסביר מדוע אנשים לעיתים קרובות מתקשים לשנות דעה גם נוכח עדות מוצקה.
מדוע אנשים מתקשים לשנות דעה לאור עדות מוצקה, לפי פסטינגר?',
'כי הזיכרון שלהם לא מאפשר למידה חדשה', 'כי המוח מייצר הצדקות להפחתת הדיסוננס במקום לשנות את האמונה', 'כי בני אדם הם שמרנים מטבעם', 'כי עדות חדשה אינה יכולה לאתגר אמונות ותיקות', 2),

(12, 4,
'ליאון פסטינגר הציג את תיאוריית הדיסוננס הקוגניטיבי — המצב הפסיכולוגי שנוצר כאשר אדם מחזיק בשתי אמונות סותרות בו-זמנית, או כאשר מעשיו סותרים את אמונותיו. לפי פסטינגר, המוח אינו יכול לסבול מתח זה לאורך זמן ולכן ישאף להפחיתו — בין אם על ידי שינוי האמונה, שינוי ההתנהגות, או — נפוץ יותר — על ידי הצדקה פסיכולוגית שמפחיתה את ה"איום" של המידע הסותר. ממצא זה מסביר מדוע אנשים לעיתים קרובות מתקשים לשנות דעה גם נוכח עדות מוצקה.
מה מהאפשרויות הבאות אינה דרך להפחית דיסוננס קוגניטיבי לפי הקטע?',
'שינוי האמונה', 'שינוי ההתנהגות', 'הצדקה פסיכולוגית', 'חיזוי עתידי של תוצאות ההתנהגות', 4);

-- Passage 3: Complex systems & emergence
INSERT INTO questions (practice_set_id, question_order, question_text, answer_option_1, answer_option_2, answer_option_3, answer_option_4, correct_answer_number) VALUES
(12, 5,
'תאוריית המערכות המורכבות עוסקת בתופעת ה"התהוות" — Emergence — שבה תכונות הכלל אינן ניתנות לניבוי מתכונות החלקים הבודדים. מושבת נמלים, למשל, מפגינה אינטליגנציה קולקטיבית ומורכבות מבנית מרשימה, אך כל נמלה בודדת פועלת על פי כמה כללים פשוטים בלבד. ההכרה בכך מאתגרת את הגישה הרדוקציוניסטית המסורתית — הניסיון להסביר תופעות מורכבות על ידי פירוקן לחלקים — ומציעה כי חלק מהתופעות ניתנות להבנה רק ברמת הכלל.
מה מאפיין תופעות "התהוות" לפי הקטע?',
'הן קל לחיזוי מהתנהגות החלקים', 'הן נגזרות ישירות מכללים מורכבים של היחידות', 'הן לא ניתנות להסבר מתכונות החלקים הבודדים', 'הן מופיעות רק במערכות ביולוגיות', 3),

(12, 6,
'תאוריית המערכות המורכבות עוסקת בתופעת ה"התהוות" — Emergence — שבה תכונות הכלל אינן ניתנות לניבוי מתכונות החלקים הבודדים. מושבת נמלים, למשל, מפגינה אינטליגנציה קולקטיבית ומורכבות מבנית מרשימה, אך כל נמלה בודדת פועלת על פי כמה כללים פשוטים בלבד. ההכרה בכך מאתגרת את הגישה הרדוקציוניסטית המסורתית — הניסיון להסביר תופעות מורכבות על ידי פירוקן לחלקים — ומציעה כי חלק מהתופעות ניתנות להבנה רק ברמת הכלל.
מה הגישה הרדוקציוניסטית ומדוע היא מאותגרת?',
'גישה המתמקדת בכלל, מאותגרת כיוון שהחלקים חשובים יותר', 'גישה הפורקת תופעות לחלקים, מאותגרת כיוון שהכלל אינו תמיד צירוף חלקיו', 'גישה הדוחה מדע ניסויי, מאותגרת על ידי הצלחות המדע', 'גישה המדגישה שיתוף פעולה, מאותגרת בגלל אינדיבידואליזם', 2);

-- Passage 4: Language & thought (Sapir-Whorf)
INSERT INTO questions (practice_set_id, question_order, question_text, answer_option_1, answer_option_2, answer_option_3, answer_option_4, correct_answer_number) VALUES
(12, 7,
'השערת סאפיר-וורף — הידועה גם כ"יחסות לשונית" — גורסת כי המבנה של השפה שאדם מדבר אינו רק כלי לביטוי מחשבות, אלא מעצב באופן פעיל את אופן חשיבתו ותפיסתו את המציאות. גרסה חזקה של ההשערה, שנדחתה ברובה על ידי המחקר המדעי, טוענת כי שפה קובעת מה ניתן לחשוב; גרסה חלשה יותר, שמקבלת תמיכה אמפירית, טוענת כי שפה משפיעה ומטה — אך לא קובעת — את תהליכי החשיבה. דוגמה קלאסית היא מחקרים המראים הבדלים בתפיסת צבעים בין דוברי שפות שמחלקות את הספקטרום הצבעוני באופן שונה.
מה ההבדל בין הגרסה החזקה לגרסה החלשה של ההשערה?',
'הגרסה החזקה מוכחת ביותר ניסויים', 'הגרסה החלשה קובעת שפה שולטת במחשבה לחלוטין', 'הגרסה החזקה טוענת לקביעה מלאה, החלשה רק להשפעה', 'אין ביניהן הבדל מהותי', 3),

(12, 8,
'השערת סאפיר-וורף — הידועה גם כ"יחסות לשונית" — גורסת כי המבנה של השפה שאדם מדבר אינו רק כלי לביטוי מחשבות, אלא מעצב באופן פעיל את אופן חשיבתו ותפיסתו את המציאות. גרסה חזקה של ההשערה, שנדחתה ברובה על ידי המחקר המדעי, טוענת כי שפה קובעת מה ניתן לחשוב; גרסה חלשה יותר, שמקבלת תמיכה אמפירית, טוענת כי שפה משפיעה ומטה — אך לא קובעת — את תהליכי החשיבה. דוגמה קלאסית היא מחקרים המראים הבדלים בתפיסת צבעים בין דוברי שפות שמחלקות את הספקטרום הצבעוני באופן שונה.
מה ניתן להסיק לגבי מחקר תפיסת הצבעים שמוזכר?',
'הוא מוכיח שהגרסה החזקה נכונה', 'הוא תומך בגרסה החלשה — שפה משפיעה על תפיסה', 'הוא מראה שכל בני האדם תופסים צבעים אחיד', 'הוא בלתי-רלוונטי להשערה', 2);

-- Passage 5: Public goods & free rider problem
INSERT INTO questions (practice_set_id, question_order, question_text, answer_option_1, answer_option_2, answer_option_3, answer_option_4, correct_answer_number) VALUES
(12, 9,
'מוצרים ציבוריים — כגון הגנה לאומית, אוויר נקי ותשתיות ציבוריות — מאופיינים בשני תכונות ייחודיות: אי-יריבות (שימוש של אחד אינו מפחית את הזמינות לאחרים) ואי-אפשרות להדיר (לא ניתן למנוע מאף אחד ליהנות מהם). בגלל תכונות אלה, השוק הפרטי נוטה לייצר אותם בחסר, שכן כל פרט רציונלי ינסה "לרכוב חינם" על מאמצי האחרים מבלי לשלם את עלות ייצורם. כשל שוק זה הוא ההצדקה הכלכלית העיקרית להתערבות ממשלתית ומיסוי לצורך מימון שירותים ציבוריים.
מה הוא "רוכב חינם" בהקשר הכלכלי?',
'אדם המשתמש בתחבורה ציבורית ללא תשלום', 'פרט הנהנה ממוצר ציבורי מבלי לשאת בעלותו', 'חברה הממחזרת משאבים ממשלתיים', 'בעל עסק המנצל פרצות מס', 2),

(12, 10,
'מוצרים ציבוריים — כגון הגנה לאומית, אוויר נקי ותשתיות ציבוריות — מאופיינים בשני תכונות ייחודיות: אי-יריבות (שימוש של אחד אינו מפחית את הזמינות לאחרים) ואי-אפשרות להדיר (לא ניתן למנוע מאף אחד ליהנות מהם). בגלל תכונות אלה, השוק הפרטי נוטה לייצר אותם בחסר, שכן כל פרט רציונלי ינסה "לרכוב חינם" על מאמצי האחרים מבלי לשלם את עלות ייצורם. כשל שוק זה הוא ההצדקה הכלכלית העיקרית להתערבות ממשלתית ומיסוי לצורך מימון שירותים ציבוריים.
מה מהווה ההצדקה הכלכלית להתערבות ממשלתית לפי הקטע?',
'הממשלה יעילה יותר מהשוק הפרטי', 'כשל השוק המוביל לייצר חסר של מוצרים ציבוריים', 'בני אדם אינם מסוגלים לשתף פעולה ללא כפייה', 'מוצרים ציבוריים יקרים מדי לייצור פרטי', 2);

-- ===== SET 13 =====

-- Passage 1: Moral philosophy - trolley problem
INSERT INTO questions (practice_set_id, question_order, question_text, answer_option_1, answer_option_2, answer_option_3, answer_option_4, correct_answer_number) VALUES
(13, 1,
'ניסוי המחשבה "בעיית העגלה" — שהציגה הפילוסופית פיליפה פוט — שואל האם מוסרי להסיט רכבת הבורחת לעבר חמישה אנשים כדי להרוג אדם אחד בלבד. רוב האנשים עונים בחיוב, וזאת בהתאם לעקרון התועלתנות — מקסום הטוב הכולל. אולם כאשר השאלה מוצגת בגרסה שונה — האם מוסרי לדחוף אדם ממוש לתוך מסלול הרכבת כדי לעצרה ולהציל חמישה — רוב האנשים עונים בשלילה, למרות שהחשבון הכמותי זהה. פרדוקס זה מדגים את הפער בין האינטואיציה המוסרית לבין העקביות הלוגית-תועלתנית.
מה הפרדוקס שמנסוי ה"עגלה" מדגים?',
'בני אדם תמיד מעדיפים להציל מספר רב יותר של חיים', 'אינטואיציה מוסרית אינה עקבית עם עקרון תועלתני אחיד', 'שאלות מוסר קשות אינן ניתנות לפתרון', 'פילוסופים מוסריים אינם מסכימים זה עם זה', 2),

(13, 2,
'ניסוי המחשבה "בעיית העגלה" — שהציגה הפילוסופית פיליפה פוט — שואל האם מוסרי להסיט רכבת הבורחת לעבר חמישה אנשים כדי להרוג אדם אחד בלבד. רוב האנשים עונים בחיוב, וזאת בהתאם לעקרון התועלתנות — מקסום הטוב הכולל. אולם כאשר השאלה מוצגת בגרסה שונה — האם מוסרי לדחוף אדם ממוש לתוך מסלול הרכבת כדי לעצרה ולהציל חמישה — רוב האנשים עונים בשלילה, למרות שהחשבון הכמותי זהה. פרדוקס זה מדגים את הפער בין האינטואיציה המוסרית לבין העקביות הלוגית-תועלתנית.
מדוע גרסת "הדחיפה" מעוררת תגובה שונה למרות שהתוצאה הכמותית זהה?',
'כי הציבור אינו מבין שהחשבון זהה', 'כי נוכחות פיזית ישירה גורמת לנסיגה מוסרית שאינה תועלתנית', 'כי חמישה חיים אינם שווים לחיים אחד בגרסה השנייה', 'כי הדחיפה בטוחה יותר מהסטת הרכבת', 2);

-- Passage 2: Behavioral economics - anchoring
INSERT INTO questions (practice_set_id, question_order, question_text, answer_option_1, answer_option_2, answer_option_3, answer_option_4, correct_answer_number) VALUES
(13, 3,
'אפקט ה"עיגון" — שתיעד כהנמן וטברסקי — הוא נטייה קוגניטיבית שבה האדם נשען יתר על המידה על פיסת המידע הראשונה שמוצגת לו בעת קבלת החלטות. בניסוי מפורסם, המשתתפים הסתובבו גלגל מזל שהוגדר מראש להראות 10 או 65, ואז נשאלו כמה מדינות אפריקאיות חברות באו"ם. אלו שראו 65 ניחשו מספרים גבוהים משמעותית מאלו שראו 10 — גם שהגלגל ברור שרנדומלי לחלוטין. ממצא זה מוכיח כי שיפוטים כמותיים מושפעים מגירויים שרירותיים, בניגוד להנחת הרציונליות.
מה הניסוי עם גלגל המזל מוכיח?',
'שאנשים מיטיבים להעריך מספרים גבוהים', 'שמידע שרירותי ובלתי-רלוונטי מטה שיפוטים כמותיים', 'שידע גיאוגרפי קשור לאינטליגנציה', 'שאנשים מעדיפים מספרים גבוהים בניחושים', 2),

(13, 4,
'אפקט ה"עיגון" — שתיעד כהנמן וטברסקי — הוא נטייה קוגניטיבית שבה האדם נשען יתר על המידה על פיסת המידע הראשונה שמוצגת לו בעת קבלת החלטות. בניסוי מפורסם, המשתתפים הסתובבו גלגל מזל שהוגדר מראש להראות 10 או 65, ואז נשאלו כמה מדינות אפריקאיות חברות באו"ם. אלו שראו 65 ניחשו מספרים גבוהים משמעותית מאלו שראו 10 — גם שהגלגל ברור שרנדומלי לחלוטין. ממצא זה מוכיח כי שיפוטים כמותיים מושפעים מגירויים שרירותיים, בניגוד להנחת הרציונליות.
מה "עיגון" קוגניטיבי לפי הניסוי?',
'חיפוש מידע רלוונטי לפני קבלת החלטה', 'הנחת בסיס הגיוניות בניחוש', 'הישענות יתר על המידע הראשוני גם אם אינו רלוונטי', 'תהליך בדיקת עובדות לפני הערכה', 3);

-- Passage 3: Evolutionary biology - altruism paradox
INSERT INTO questions (practice_set_id, question_order, question_text, answer_option_1, answer_option_2, answer_option_3, answer_option_4, correct_answer_number) VALUES
(13, 5,
'האלטרואיזם — התנהגות של הקרבה עצמית לטובת אחרים — יצר פרדוקס אבולוציוני: כיצד ייבחר על ידי האבולוציה מנגנון המפחית את כושר ההשרדות של האינדיבידואל? וילאם המילטון הציע פתרון בתאוריית "מיון הקרובים" — ברירה שמטיבה עם גנים משותפים. אמנם פרט מסוים עשוי לאבד, אך גנים זהים ישרדו אצל קרוביו. ג''ון מיינארד סמית'' הרחיב זאת ב"אלטרואיזם הדדי" — שיתוף פעולה בין פרטים שאינם קרובים, המבוסס על ציפייה להדדיות עתידית. שני המנגנונים מדגימים כיצד שיתוף פעולה עשוי להיות אסטרטגיה אבולוציונית יעילה.
מה "מיון הקרובים" של המילטון מסביר?',
'מדוע בני משפחה קרובים לעתים יורשים יותר רכוש', 'מדוע אלטרואיזם כלפי קרובי משפחה עשוי להועיל להפצת גנים משותפים', 'מדוע בעלי חיים בוחרים בן-זוג מקרוב גנטי', 'מדוע אוכלוסיות מבודדות מתפתחות מהר יותר', 2),

(13, 6,
'האלטרואיזם — התנהגות של הקרבה עצמית לטובת אחרים — יצר פרדוקס אבולוציוני: כיצד ייבחר על ידי האבולוציה מנגנון המפחית את כושר ההשרדות של האינדיבידואל? וילאם המילטון הציע פתרון בתאוריית "מיון הקרובים" — ברירה שמטיבה עם גנים משותפים. אמנם פרט מסוים עשוי לאבד, אך גנים זהים ישרדו אצל קרוביו. ג''ון מיינארד סמית'' הרחיב זאת ב"אלטרואיזם הדדי" — שיתוף פעולה בין פרטים שאינם קרובים, המבוסס על ציפייה להדדיות עתידית. שני המנגנונים מדגימים כיצד שיתוף פעולה עשוי להיות אסטרטגיה אבולוציונית יעילה.
מה ההבדל בין "מיון הקרובים" ל"אלטרואיזם הדדי"?',
'הראשון עוסק בקרובים גנטית, השני בשיתוף פעולה עם זרים', 'הראשון אבולוציוני, השני תרבותי בלבד', 'הראשון מוגבל לבעלי חיים, השני ייחודי לבני אדם', 'הראשון מחקרי, השני תיאורטי בלבד', 1);

-- Passage 4: Political philosophy - social contract
INSERT INTO questions (practice_set_id, question_order, question_text, answer_option_1, answer_option_2, answer_option_3, answer_option_4, correct_answer_number) VALUES
(13, 7,
'תורת החוזה החברתי, שפותחה על ידי הוגים כהובס, לוק ורוסו, מציעה כי הלגיטימיות של השלטון נובעת מהסכמה — מרומזת או מפורשת — של הנשלטים. הובס טען כי ללא שלטון מרכזי, חיי האדם הם "בדידים, דלים, מזוהמים, אכזריים וקצרים", ולכן הפרטים מסכימים לוותר על חירות בתמורה לביטחון. לוק, לעומתו, ראה בשלטון נאמן של העם, ונתן לאנשים את הזכות למרוד בשלטון שהפר את החוזה. הבדל זה בבסיס תפיסת החוזה משפיע ישירות על אופי הזכויות הפוליטיות שכל הוגה מעניק לאזרח.
מה ההבדל המהותי בין עמדות הובס ולוק לגבי החוזה החברתי?',
'הובס מאמין בדמוקרטיה, לוק במלוכה', 'הובס רואה בשלטון מרות הכרחית, לוק רואה בו נאמן הניתן לביטול', 'שניהם מאמינים בזכות המרד אך מסיבות שונות', 'לוק דוחה לחלוטין את מושג החוזה', 2),

(13, 8,
'תורת החוזה החברתי, שפותחה על ידי הוגים כהובס, לוק ורוסו, מציעה כי הלגיטימיות של השלטון נובעת מהסכמה — מרומזת או מפורשת — של הנשלטים. הובס טען כי ללא שלטון מרכזי, חיי האדם הם "בדידים, דלים, מזוהמים, אכזריים וקצרים", ולכן הפרטים מסכימים לוותר על חירות בתמורה לביטחון. לוק, לעומתו, ראה בשלטון נאמן של העם, ונתן לאנשים את הזכות למרוד בשלטון שהפר את החוזה. הבדל זה בבסיס תפיסת החוזה משפיע ישירות על אופי הזכויות הפוליטיות שכל הוגה מעניק לאזרח.
מדוע לפי הובס הפרטים מוכנים לוותר על חירות?',
'כי השלטון מבטיח שגשוג כלכלי', 'כי הם נוצרו להיות נתינים', 'כי ללא שלטון, חייהם יהיו חסרי ביטחון ואכזריים', 'כי הם מאמינים בחובה מוסרית לציית', 3);

-- Passage 5: Network effects & monopoly
INSERT INTO questions (practice_set_id, question_order, question_text, answer_option_1, answer_option_2, answer_option_3, answer_option_4, correct_answer_number) VALUES
(13, 9,
'אפקטי רשת — התגברות ערך מוצר או שירות עם גידול מספר משתמשיו — מסבירים מדוע שווקים טכנולוגיים רבים נוטים לריכוזיות קיצונית. ברגע ש"נקודת הטיפה" נחצית ופלטפורמה הופכת לדומינטית, יתרונותיה מתחזקים בלולאה חיובית: יותר משתמשים מושכים יותר ספקי שירות ומוכרים, שמושכים עוד משתמשים. בשוק כזה, פלטפורמה מתחרה שמציעה מוצר טוב יותר אינה מבטיחה בהכרח הצלחה, שכן ה"נעילה" (lock-in) המבנית עשויה להיות עצומה. זו הסיבה שרגולטורים עוסקים יותר ויותר בשאלת כוח השוק של ענקיות הטכנולוגיה.
מדוע פלטפורמה מתחרה עם מוצר טוב יותר עשויה להיכשל?',
'כי הצרכנים אינם מסוגלים להעריך איכות', 'כי השוק הטכנולוגי מוסדר כנגד תחרות', 'כי אפקטי הרשת יוצרים יתרון מובנה לפלטפורמה הדומינטית', 'כי עלויות הפיתוח גבוהות מדי', 3),

(13, 10,
'אפקטי רשת — התגברות ערך מוצר או שירות עם גידול מספר משתמשיו — מסבירים מדוע שווקים טכנולוגיים רבים נוטים לריכוזיות קיצונית. ברגע ש"נקודת הטיפה" נחצית ופלטפורמה הופכת לדומינטית, יתרונותיה מתחזקים בלולאה חיובית: יותר משתמשים מושכים יותר ספקי שירות ומוכרים, שמושכים עוד משתמשים. בשוק כזה, פלטפורמה מתחרה שמציעה מוצר טוב יותר אינה מבטיחה בהכרח הצלחה, שכן ה"נעילה" (lock-in) המבנית עשויה להיות עצומה. זו הסיבה שרגולטורים עוסקים יותר ויותר בשאלת כוח השוק של ענקיות הטכנולוגיה.
מה "לולאה חיובית" בהקשר שווקי פלטפורמות?',
'מנגנון שבו צמיחה מאטה עם הזמן', 'מנגנון שבו כל גידול מחזק את עצמו', 'מנגנון ממשלתי לעידוד תחרות', 'פידבק מהמשתמשים המשפר את המוצר', 2);

-- ===== SET 14 =====

-- Passage 1: Quantum mechanics & uncertainty
INSERT INTO questions (practice_set_id, question_order, question_text, answer_option_1, answer_option_2, answer_option_3, answer_option_4, correct_answer_number) VALUES
(14, 1,
'עקרון אי-הוודאות של הייזנברג קובע כי לא ניתן לדעת בו-זמנית, בדיוק מלא, הן את המיקום הן את התאוצה של חלקיק קוונטי. ככל שנמדוד את המיקום בדיוק גבוה יותר, כך תגדל אי-הוודאות לגבי התאוצה, ולהיפך. עקרון זה אינו נובע ממגבלות טכנולוגיות של מכשירי המדידה, אלא מהמבנה הבסיסי של הטבע עצמו. ההשלכה הפילוסופית עמוקה: המציאות הקוונטית היא מהותית אינדטרמיניסטית — לא כל מה שקורה בטבע נקבע מראש על ידי מצב קודם.
מה ההשלכה הפילוסופית של עקרון הייזנברג לגבי אופי המציאות?',
'המציאות פשוטה יותר ממה שנחשב', 'קיים אינדטרמיניזם מהותי בטבע', 'ניתן לשפר את כלי המדידה עד לדיוק מלא', 'הפיזיקה הקוונטית אינה חלה על עולם הניסיון היומיומי', 2),

(14, 2,
'עקרון אי-הוודאות של הייזנברג קובע כי לא ניתן לדעת בו-זמנית, בדיוק מלא, הן את המיקום הן את התאוצה של חלקיק קוונטי. ככל שנמדוד את המיקום בדיוק גבוה יותר, כך תגדל אי-הוודאות לגבי התאוצה, ולהיפך. עקרון זה אינו נובע ממגבלות טכנולוגיות של מכשירי המדידה, אלא מהמבנה הבסיסי של הטבע עצמו. ההשלכה הפילוסופית עמוקה: המציאות הקוונטית היא מהותית אינדטרמיניסטית — לא כל מה שקורה בטבע נקבע מראש על ידי מצב קודם.
מה מייחד את עקרון אי-הוודאות לעומת "רק" מגבלת מכשיר מדידה?',
'הוא תקף רק לחלקיקים כבדים', 'הוא נובע מהמבנה הפיזיקלי הבסיסי ולא ממגבלה טכנולוגית', 'הוא ניתן לפתרון עם טכנולוגיה עתידית', 'הוא חל רק בתנאי ניסוי מיוחדים', 2);

-- Passage 2: Moral hazard in economics
INSERT INTO questions (practice_set_id, question_order, question_text, answer_option_1, answer_option_2, answer_option_3, answer_option_4, correct_answer_number) VALUES
(14, 3,
'סיכון מוסרי — moral hazard — הוא תופעה שבה הגנה מפני סיכון שינתה את אופי ההתנהגות של המוגן. הדוגמה הקלאסית: ביטוח רכב מניע חלק מהמבוטחים לנהוג בזהירות פחותה, שכן ייוחס הנזק לחברת הביטוח. בשוק הפיננסי, בנקים גדולים — הידועים כ"גדולים מכדי להיפול" — נוטים לנטילת סיכונים מוגזמת כיוון שהם מניחים כי הממשלה תציל אותם מקריסה. ההבדל המהותי בין ביטוח לבין סיכון מוסרי הוא שהראשון מגן מפני אי-ודאות קיימת, בעוד השני יוצר אי-ודאות חדשה על ידי שינוי התמריצים.
מה ה"סיכון המוסרי" שהקטע מתאר?',
'סיכון הנובע מהתנהגות בלתי-אתית מכוונת', 'שינוי שלילי בהתנהגות הנגרם על ידי הגנה מסיכון', 'חוסר ביטוח של אוכלוסיות מוחלשות', 'סיכון שאינו ניתן לכימות מדויק', 2),

(14, 4,
'סיכון מוסרי — moral hazard — הוא תופעה שבה הגנה מפני סיכון שינתה את אופי ההתנהגות של המוגן. הדוגמה הקלאסית: ביטוח רכב מניע חלק מהמבוטחים לנהוג בזהירות פחותה, שכן ייוחס הנזק לחברת הביטוח. בשוק הפיננסי, בנקים גדולים — הידועים כ"גדולים מכדי להיפול" — נוטים לנטילת סיכונים מוגזמת כיוון שהם מניחים כי הממשלה תציל אותם מקריסה. ההבדל המהותי בין ביטוח לבין סיכון מוסרי הוא שהראשון מגן מפני אי-ודאות קיימת, בעוד השני יוצר אי-ודאות חדשה על ידי שינוי התמריצים.
מה ההבדל שהקטע מגדיר בין ביטוח לסיכון מוסרי?',
'ביטוח יקר יותר מסיכון מוסרי', 'ביטוח מגן מאי-ודאות קיימת; סיכון מוסרי יוצר אי-ודאות חדשה', 'סיכון מוסרי חל רק על בנקים', 'ביטוח גרם לסיכון מוסרי בעבר אך לא כיום', 2);

-- Passage 3: Dunning-Kruger effect
INSERT INTO questions (practice_set_id, question_order, question_text, answer_option_1, answer_option_2, answer_option_3, answer_option_4, correct_answer_number) VALUES
(14, 5,
'אפקט דנינג-קרוגר הוא הטיה קוגניטיבית שבה אנשים בעלי ידע מוגבל בתחום מסוים נוטים להעריך את יכולתם יתר על המידה, בעוד מומחים אמיתיים נוטים לזלזל בכישוריהם. הסיבה לכך, לפי החוקרים, היא שאותה בורות הגורמת לאדם לשגות גם מונעת ממנו לזהות את שגיאותיו. מומחים, לעומת זאת, מודעים למורכבות התחום ולמה שעדיין אינם יודעים, ולכן אינם בטוחים בעצמם יתר על המידה. ממצא זה מוליד אפוריזם שנהפך לנפוץ: "ככל שמישהו בטוח יותר שהוא צודק, כך כדאי לבדוק בזהירות יותר את טענותיו."
מה הגורם לאנשים בעלי ידע מוגבל להעריך יתר את עצמם?',
'ביטחון עצמי גבוה מולד', 'חוסר יכולת לזהות את שגיאותיהם בגלל אותה בורות', 'חינוך לקוי שמעודד ביטחון עצמי', 'היעדר מנגנון שוואתי חברתי', 2),

(14, 6,
'אפקט דנינג-קרוגר הוא הטיה קוגניטיבית שבה אנשים בעלי ידע מוגבל בתחום מסוים נוטים להעריך את יכולתם יתר על המידה, בעוד מומחים אמיתיים נוטים לזלזל בכישוריהם. הסיבה לכך, לפי החוקרים, היא שאותה בורות הגורמת לאדם לשגות גם מונעת ממנו לזהות את שגיאותיו. מומחים, לעומת זאת, מודעים למורכבות התחום ולמה שעדיין אינם יודעים, ולכן אינם בטוחים בעצמם יתר על המידה. ממצא זה מוליד אפוריזם שנהפך לנפוץ: "ככל שמישהו בטוח יותר שהוא צודק, כך כדאי לבדוק בזהירות יותר את טענותיו."
מדוע מומחים אמיתיים נוטים לזלזל בכישוריהם?',
'כי הם חסרי ביטחון מטבעם', 'כי הם מודעים למורכבות ולפערי הידע שלהם', 'כי הם חוששים מביקורת עמיתים', 'כי הם עסוקים מדי כדי להרהר ביכולותיהם', 2);

-- Passage 4: Tragedy of the commons
INSERT INTO questions (practice_set_id, question_order, question_text, answer_option_1, answer_option_2, answer_option_3, answer_option_4, correct_answer_number) VALUES
(14, 7,
'הטרגדיה של המשאב המשותף — שתיאר גרט הרדין — מתרחשת כאשר פרטים רציונליים המשתמשים במשאב משותף (כגון שטח מרעה, דגה, או אוויר נקי) מנצלים אותו יתר על המידה, גם אם הדבר מוביל לקריסתו. כל פרט מרוויח מניצול נוסף את הרווח המלא, בעוד שעלות הנזק מחולקת בין כולם. מבחינה פרטנית-רציונלית, אין תמריץ לריסון עצמי — וכך כולם מפסידים. הרדין הציג שתי פתרונות עיקריים: הפרטת המשאב, שמייצרת בעלות ותמריץ לשמירה עליו, או הסדרה ממשלתית הכופה מגבלות על הניצול.
מה עיקרון ה"טרגדיה" בטרגדיית המשאב המשותף?',
'תחרות יוצרת חדשנות אך הורסת ערבות', 'אינטרס פרטי-רציונלי גורם לנזק קולקטיבי', 'ממשלות אינן מסוגלות לנהל משאבים ביעילות', 'משאבים משותפים מאפשרים שוויון כלכלי', 2),

(14, 8,
'הטרגדיה של המשאב המשותף — שתיאר גרט הרדין — מתרחשת כאשר פרטים רציונליים המשתמשים במשאב משותף (כגון שטח מרעה, דגה, או אוויר נקי) מנצלים אותו יתר על המידה, גם אם הדבר מוביל לקריסתו. כל פרט מרוויח מניצול נוסף את הרווח המלא, בעוד שעלות הנזק מחולקת בין כולם. מבחינה פרטנית-רציונלית, אין תמריץ לריסון עצמי — וכך כולם מפסידים. הרדין הציג שתי פתרונות עיקריים: הפרטת המשאב, שמייצרת בעלות ותמריץ לשמירה עליו, או הסדרה ממשלתית הכופה מגבלות על הניצול.
מדוע הפרטה יכולה לפתור את הבעיה לפי הרדין?',
'כי חברות פרטיות יעילות יותר', 'כי הבעלות מייצרת תמריץ לשמירה על המשאב לטווח ארוך', 'כי הממשלה לא יכולה לנהל משאבים', 'כי שוק חופשי מוביל תמיד לתוצאות אופטימליות', 2);

-- Passage 5: Diffusion of responsibility
INSERT INTO questions (practice_set_id, question_order, question_text, answer_option_1, answer_option_2, answer_option_3, answer_option_4, correct_answer_number) VALUES
(14, 9,
'תפוצת האחריות — ה"אפקט הצופה" — היא תופעה פסיכולוגית שלפיה ההסתברות שאדם יסייע בחירום יורדת ככל שנוכחים בו יותר עדים. בניגוד לאינטואיציה, ריבוי נוכחים אינו מגביר את הסיוע — אלא מפחיתו. הסיבה: כל עד מניח שמישהו אחר ידאג לפעול, ועצם הנוכחות של האחרים מדללת את תחושת האחריות האישית. ניסוי מפורסם הראה כי אנשים שסברו שהם היחידים שמאזינים לדיבור נפגע פעלו מהר הרבה יותר מאלו שסברו שישנם עדים נוספים.
מדוע ריבוי עדים מפחית את הסיוע לפי הקטע?',
'כי הקהל יוצר פאניקה המקשה על פעולה', 'כי כל פרט מניח שמישהו אחר יפעל ואחריותו מתדללת', 'כי אנשים מתביישים לבקש עזרה בפומבי', 'כי קהל גדול מקשה על גישה לנפגע', 2),

(14, 10,
'תפוצת האחריות — ה"אפקט הצופה" — היא תופעה פסיכולוגית שלפיה ההסתברות שאדם יסייע בחירום יורדת ככל שנוכחים בו יותר עדים. בניגוד לאינטואיציה, ריבוי נוכחים אינו מגביר את הסיוע — אלא מפחיתו. הסיבה: כל עד מניח שמישהו אחר ידאג לפעול, ועצם הנוכחות של האחרים מדללת את תחושת האחריות האישית. ניסוי מפורסם הראה כי אנשים שסברו שהם היחידים שמאזינים לדיבור נפגע פעלו מהר הרבה יותר מאלו שסברו שישנם עדים נוספים.
מה ניתן להסיק מהניסוי המתואר בקטע?',
'תחושת בדידות מגבירה יכולת קבלת החלטות', 'תפיסת ייחודיות של העד מגבירה נטייה לסיוע', 'אנשים אמיצים יותר כשנוכחים עדים', 'קהלים גדולים מגיבים מהר יותר לחירום', 2);

-- ===== SET 15 =====

-- Passage 1: Survivorship bias
INSERT INTO questions (practice_set_id, question_order, question_text, answer_option_1, answer_option_2, answer_option_3, answer_option_4, correct_answer_number) VALUES
(15, 1,
'הטיית ה"שרידים" — survivorship bias — מתרחשת כאשר מסקנות נגזרות מנתונים שכוללים רק את מי ש"שרד" תהליך מסוים, ומתעלמות מאלו שלא שרדו. דוגמה קלאסית: ניתוח מה שמשותף לחברות הצלחה עלול להוביל למסקנות שגויות אם מתעלמים מחברות שנכשלו שהיו להן אותם מאפיינים. מחקר מלחמת העולם השנייה שניסה לחזק את שריון המטוסים לפי אזורי הפגיעה שנצפו על מטוסים ששבו — בעוד שהאזורים שבהם פגיעה גרמה למטוסים שלא שבו לא נכללו — הוא מקרה מקורי. הסטטיסטיקאי אברהם וולד הבין כי הטיפול צריך להינתן דווקא לאזורים ללא פגיעות על השרידים.
מה הוולד הבין שאחרים החמיצו?',
'שמטוסים שרדו הודות לשריון כבד', 'שנתוני הפגיעות על השרידים משקפים את מה שניתן לעמוד בו, לא את האזורים הקריטיים', 'שהאויב ניסה לפגוע באזורים ספציפיים', 'שיש להסיר שריון כדי לשפר ניידות', 2),

(15, 2,
'הטיית ה"שרידים" — survivorship bias — מתרחשת כאשר מסקנות נגזרות מנתונים שכוללים רק את מי ש"שרד" תהליך מסוים, ומתעלמות מאלו שלא שרדו. דוגמה קלאסית: ניתוח מה שמשותף לחברות הצלחה עלול להוביל למסקנות שגויות אם מתעלמים מחברות שנכשלו שהיו להן אותם מאפיינים. מחקר מלחמת העולם השנייה שניסה לחזק את שריון המטוסים לפי אזורי הפגיעה שנצפו על מטוסים ששבו — בעוד שהאזורים שבהם פגיעה גרמה למטוסים שלא שבו לא נכללו — הוא מקרה מקורי. הסטטיסטיקאי אברהם וולד הבין כי הטיפול צריך להינתן דווקא לאזורים ללא פגיעות על השרידים.
מה הסכנה בניתוח מאפיינים של חברות מצליחות בלבד?',
'קשה לאסוף נתונים על חברות מצליחות', 'ייתכן שאותם מאפיינים קיימים בחברות שנכשלו, ואינם גורם ההצלחה', 'חברות מצליחות אינן מוכנות לחלוק מידע', 'מאפיינים של הצלחה משתנים לעתים קרובות', 2);

-- Passage 2: Status quo bias & default effects
INSERT INTO questions (practice_set_id, question_order, question_text, answer_option_1, answer_option_2, answer_option_3, answer_option_4, correct_answer_number) VALUES
(15, 3,
'הטיית הסטטוס קוו היא נטיית בני האדם להעדיף את המצב הקיים על פני שינוי, גם כאשר השינוי היה מועיל אובייקטיבית. החוקרים ת''אלר וסאנשטיין הוכיחו כי ניתן לנצל הטיה זו לטובת הציבור באמצעות "ארכיטקטורת הבחירה" — עיצוב ברירת המחדל כך שתהיה האפשרות הרצויה. כאשר המדינה ניסתה לעודד תרומת איברים, מדינות שאימצו מדיניות "אי-הצטרפות" (Opt-out) — שבה תרומה היא ברירת המחדל — הגיעו לשיעורי תרומה של 90% ומעלה, בעוד מדינות "הצטרפות" (Opt-in) הגיעו לכ-20% בלבד. ההבדל אינו בשכנוע, אלא בבחירת נקודת המוצא.
מה "ארכיטקטורת הבחירה" מנצלת?',
'ביורוקרטיה ממשלתית להטמעת מדיניות', 'הטיה כלפי ברירת המחדל כדי לכוון התנהגות', 'תמריצים כלכליים לשינוי דעה', 'חינוך והסברה ציבורית לטווח ארוך', 2),

(15, 4,
'הטיית הסטטוס קוו היא נטיית בני האדם להעדיף את המצב הקיים על פני שינוי, גם כאשר השינוי היה מועיל אובייקטיבית. החוקרים ת''אלר וסאנשטיין הוכיחו כי ניתן לנצל הטיה זו לטובת הציבור באמצעות "ארכיטקטורת הבחירה" — עיצוב ברירת המחדל כך שתהיה האפשרות הרצויה. כאשר המדינה ניסתה לעודד תרומת איברים, מדינות שאימצו מדיניות "אי-הצטרפות" (Opt-out) — שבה תרומה היא ברירת המחדל — הגיעו לשיעורי תרומה של 90% ומעלה, בעוד מדינות "הצטרפות" (Opt-in) הגיעו לכ-20% בלבד. ההבדל אינו בשכנוע, אלא בבחירת נקודת המוצא.
מה ניתן להסיק מהנתונים בדבר תרומת האיברים?',
'בני אדם אינם אוהבים תרומת איברים בעקרון', 'מדינות Opt-out ניהלו קמפיינים טובים יותר', 'ברירת המחדל משפיעה דרמטית על ההתנהגות בפועל', 'שיעורי תרומה גבוהים תלויים בגורמים תרבותיים בלבד', 3);

-- Passage 3: Confirmation bias & filter bubbles
INSERT INTO questions (practice_set_id, question_order, question_text, answer_option_1, answer_option_2, answer_option_3, answer_option_4, correct_answer_number) VALUES
(15, 5,
'הטיית האישור — confirmation bias — היא נטיית בני האדם לחפש, לפרש ולזכור מידע שמאשש את אמונותיהם הקיימות, תוך התעלמות ממידע סותר. ברשת האינטרנט, אלגוריתמים של מנועי חיפוש ורשתות חברתיות מגבירים הטיה זו: הם למדו להציג תוכן שהמשתמש אהב בעבר, ויוצרים "בועות מסנן" — סביבות מידע המחזקות את השקפת העולם הקיימת. הדאגה הדמוקרטית היא שאזרחים החיים ב"בועות" שונות אינם חולקים עובדות בסיסיות משותפות, מה שמקשה על דיון רציונלי ועל גיבוש קונסנזוס חברתי.
מדוע בועות מסנן מהוות דאגה דמוקרטית?',
'כי הן מסיחות את תשומת הלב מעניינים ציבוריים', 'כי הן פוגעות ביכולת אזרחים לשתף בסיס עובדתי משותף', 'כי הן מאפשרות תעמולה ממשלתית', 'כי הן מגבילות את חופש הביטוי', 2),

(15, 6,
'הטיית האישור — confirmation bias — היא נטיית בני האדם לחפש, לפרש ולזכור מידע שמאשש את אמונותיהם הקיימות, תוך התעלמות ממידע סותר. ברשת האינטרנט, אלגוריתמים של מנועי חיפוש ורשתות חברתיות מגבירים הטיה זו: הם למדו להציג תוכן שהמשתמש אהב בעבר, ויוצרים "בועות מסנן" — סביבות מידע המחזקות את השקפת העולם הקיימת. הדאגה הדמוקרטית היא שאזרחים החיים ב"בועות" שונות אינם חולקים עובדות בסיסיות משותפות, מה שמקשה על דיון רציונלי ועל גיבוש קונסנזוס חברתי.
כיצד האלגוריתמים מחמירים את הטיית האישור?',
'על ידי חסימת תוכן שנוי במחלוקת', 'על ידי הצגת תוכן שמחזק העדפות קיימות של המשתמש', 'על ידי עידוד שיח אנונימי ותוקפני', 'על ידי מסחור של מידע אישי', 2);

-- Passage 4: Sunk cost fallacy
INSERT INTO questions (practice_set_id, question_order, question_text, answer_option_1, answer_option_2, answer_option_3, answer_option_4, correct_answer_number) VALUES
(15, 7,
'כשל "העלות השקועה" הוא נטייה להמשיך בפעולה בגלל משאבים שכבר הושקעו בה — זמן, כסף, מאמץ — גם כאשר ניתוח עתידי ענייני מצביע על כך שהמשך הפעולה אינו כדאי. הטעות הרציונלית היא שהעלות כבר הוצאה ואינה ניתנת לשחזור — ולכן לא אמורה להשפיע על החלטות עתידיות. לדוגמה: ממשלות ממשיכות לממן פרויקטים תשתיתיים כושלים "כי כבר השקענו סכום כה גדול", ואנשים ממשיכים לצפות בסרט משעמם כי כבר שילמו על הכרטיס. כלכלה רציונלית דורשת להתעלם מעלויות שקועות ולהחליט אך ורק על בסיס עלות-תועלת עתידית.
מהי "עלות שקועה" ומדוע לא אמורה להשפיע על החלטות?',
'עלות בלתי-צפויה שאי אפשר לתכנן עבורה', 'עלות שכבר הוצאה ואינה ניתנת לשחזור, ולכן אינה רלוונטית לעתיד', 'עלות חבויה שחברות מסתירות מהמשקיעים', 'עלות גבוהה במיוחד שדורשת אישור מיוחד', 2),

(15, 8,
'כשל "העלות השקועה" הוא נטייה להמשיך בפעולה בגלל משאבים שכבר הושקעו בה — זמן, כסף, מאמץ — גם כאשר ניתוח עתידי ענייני מצביע על כך שהמשך הפעולה אינו כדאי. הטעות הרציונלית היא שהעלות כבר הוצאה ואינה ניתנת לשחזור — ולכן לא אמורה להשפיע על החלטות עתידיות. לדוגמה: ממשלות ממשיכות לממן פרויקטים תשתיתיים כושלים "כי כבר השקענו סכום כה גדול", ואנשים ממשיכים לצפות בסרט משעמם כי כבר שילמו על הכרטיס. כלכלה רציונלית דורשת להתעלם מעלויות שקועות ולהחליט אך ורק על בסיס עלות-תועלת עתידית.
מה הכלכלה הרציונלית דורשת לפי הקטע?',
'להכיר בעלויות שקועות ולהתאים את ציפיות הרווח', 'להחליט על בסיס עלות-תועלת עתידית בלבד תוך התעלמות מהעבר', 'להגדיל השקעה בפרויקטים כושלים כדי להפוך אותם לרווחיים', 'לתמחר מוצרים ושירותים לפי עלות ייצורם ההיסטורית', 2);

-- Passage 5: Availability heuristic & risk perception
INSERT INTO questions (practice_set_id, question_order, question_text, answer_option_1, answer_option_2, answer_option_3, answer_option_4, correct_answer_number) VALUES
(15, 9,
'ה"היוריסטיקה של הזמינות" — שטבעו כהנמן וטברסקי — היא קיצור דרך מנטלי שבו האדם אומד את שכיחות או סיכון של אירוע לפי הקלות שבה דוגמאות עולות בדעתו. ככל שדוגמאות לאירוע קיצוני נגישות יותר לזיכרון — בין אם בשל חשיפה תקשורתית ובין אם בשל חוויה אישית — כך ייתפס הסיכון כגבוה יותר, גם אם הסטטיסטיקה הממשית אומרת ההפך. לכן, לאחר תאונת מטוס מדווחת, שיעורי ביטוח הנסיעות עולים דרמטית — בעוד שנסיעה ברכב, שסטטיסטית מסוכנת הרבה יותר, אינה מעוררת אותה דאגה.
מה מסביר עליית שיעורי ביטוח הנסיעות לאחר תאונת מטוס?',
'חברות הביטוח מנצלות את ההזדמנות להרוויח', 'הסיכון הממשי של טיסה עולה לאחר תאונה', 'נגישות הדוגמה לזיכרון מנפחת את תחושת הסיכון', 'אנשים הופכים לזהירים יותר בכלל לאחר תאונות', 3),

(15, 10,
'ה"היוריסטיקה של הזמינות" — שטבעו כהנמן וטברסקי — היא קיצור דרך מנטלי שבו האדם אומד את שכיחות או סיכון של אירוע לפי הקלות שבה דוגמאות עולות בדעתו. ככל שדוגמאות לאירוע קיצוני נגישות יותר לזיכרון — בין אם בשל חשיפה תקשורתית ובין אם בשל חוויה אישית — כך ייתפס הסיכון כגבוה יותר, גם אם הסטטיסטיקה הממשית אומרת ההפך. לכן, לאחר תאונת מטוס מדווחת, שיעורי ביטוח הנסיעות עולים דרמטית — בעוד שנסיעה ברכב, שסטטיסטית מסוכנת הרבה יותר, אינה מעוררת אותה דאגה.
מה ההפרדוקס שהקטע מדגים לגבי תפיסת הסיכון?',
'אנשים מדויקים בהערכת סיכונים נדירים', 'דווקא האמצעי הסטטיסטי הבטוח יותר נתפס כמסוכן יותר', 'חשיפה תקשורתית מפחיתה חרדה', 'אנשים עם ניסיון אישי מעריכים סיכונים טוב יותר', 2);
